questionvariables.text:
/* ===== Parameter set selection ===== */
set: rand(3)+1;

/* ===== Given values ===== */
ell_cm: if set=1 then 30 else if set=2 then 25 else 40;
v:      if set=1 then 8  else if set=2 then 5  else 10;
B:      if set=1 then 0.5 else if set=2 then 0.8 else 0.3;
R:      if set=1 then 6  else if set=2 then 4  else 5;

/* ===== Derived values ===== */
ell: ell_cm/100;
emf_val: float(B*ell*v);
I_val: float(emf_val/R);
P_elec: float(I_val^2*R);

/* ===== Common-error reference values ===== */
P_wrong_IR: float(I_val*R);  /* student computed I*R instead of I^2*R */

/* ===== Teacher answers ===== */
ta1: float(emf_val);
ta2: float(I_val);
ta3: float(P_elec);

/* Part (d) MCQ: Current direction through resistor */
ta4: [[1, true, "Counterclockwise (downward through R) — opposes increasing flux into the page"],
      [2, false, "Clockwise (upward through R) — aids the increasing flux into the page"],
      [3, false, "No current flows — the bar is not part of a closed circuit"],
      [4, false, "The direction alternates as the bar moves"]];
ta4_correct: 1;

/* Part (e) MCQ: What happens to power when ell doubles and v halves? */
/* P = (B*ell*v)^2/R. With 2*ell and v/2: P' = (B*2*ell*v/2)^2/R = (B*ell*v)^2/R = P unchanged */
ta5: [[1, true, "The power stays the same — P = (Bℓv)²/R, and doubling ℓ while halving v leaves Bℓv unchanged"],
      [2, false, "The power doubles — longer bar means more EMF"],
      [3, false, "The power halves — slower bar means less EMF"],
      [4, false, "The power quadruples — P is proportional to ℓ²"]];
ta5_correct: 1;

feedbackvariables.text:
sa1_float: float(ans1);
ref1_float: float(ta1);
prt1_oom_ok: if (abs(ref1_float) > 1.0e-30 and abs(sa1_float) > 1.0e-30 and (abs(sa1_float/ref1_float - 10) < 1.5 or abs(sa1_float/ref1_float - 0.1) < 0.015)) then true else false;

sa2_float: float(ans2);
ref2_float: float(ta2);
prt2_oom_ok: if (abs(ref2_float) > 1.0e-30 and abs(sa2_float) > 1.0e-30 and (abs(sa2_float/ref2_float - 10) < 1.5 or abs(sa2_float/ref2_float - 0.1) < 0.015)) then true else false;

sa3_float: float(ans3);
ref3_float: float(ta3);
prt3_oom_ok: if (abs(ref3_float) > 1.0e-30 and abs(sa3_float) > 1.0e-30 and (abs(sa3_float/ref3_float - 10) < 1.5 or abs(sa3_float/ref3_float - 0.1) < 0.015)) then true else false;
prt3_IR_error: if (abs(P_wrong_IR) > 1.0e-30 and abs(sa3_float) > 1.0e-30 and abs(sa3_float/P_wrong_IR - 1) < 0.05) then true else false;
